@page "/category/{CategoryName}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <p class="text-muted">No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-4 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="text-muted">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-link mt-3">← Back to Categories</a>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private List<RecipeShare.Models.Recipe> recipes = new();

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: <a href="/category/@recipe.Category">@recipe.Category</a></p>

    <StarRating RecipeId="recipe.Id" CurrentAverage="recipe.AverageRating" CurrentCount="recipe.RatingCount" />

    <h3 class="mt-4">Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@ingredient.Trim()</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.Trim();
            if (text.Length > 2 && text[1] == '.' && char.IsDigit(text[0]))
            {
                text = text[2..].Trim();
            }
            else if (text.Length > 3 && text[2] == '.' && char.IsDigit(text[0]) && char.IsDigit(text[1]))
            {
                text = text[3..].Trim();
            }
            <li>@text</li>
        }
    </ol>

    <a href="/category/@recipe.Category" class="btn btn-link mt-3">← Back to @recipe.Category recipes</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeShare.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="my-3 p-3 border rounded" style="display: inline-block;">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button"
              style="font-size: 1.5rem; cursor: pointer;"
              @onclick="() => SubmitRating(star)"
              title="@star star(s)">
            @(star <= hoveredStar ? "★" : "☆")
        </span>
    }

    @if (submitted)
    {
        <span class="ms-2 text-success">✓ Thanks for rating!</span>
    }

    <div class="mt-1 text-muted small">
        ⭐ @currentAverage / 5 (@currentCount ratings)
    </div>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int CurrentCount { get; set; }

    private int hoveredStar;
    private bool submitted;
    private double currentAverage;
    private int currentCount;

    protected override void OnParametersSet()
    {
        currentAverage = CurrentAverage;
        currentCount = CurrentCount;
    }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            currentAverage = recipe.AverageRating;
            currentCount = recipe.RatingCount;
        }
        hoveredStar = stars;
        submitted = true;
    }
}

